create table if not exists public.profiles(id uuid primary key default gen_random_uuid(),name text not null,email text not null unique,password text not null,status text not null default 'pending',registered_at timestamptz default now(),approved_at timestamptz);create table if not exists public.exams(id text primary key,name text not null,subject text not null,duration integer not null default 30,questions integer not null default 0,questions_data jsonb not null default '[]',created_at timestamptz default now());create table if not exists public.results(id uuid primary key default gen_random_uuid(),student_id uuid,exam_id text,student_name text,student_email text,score integer,total integer,pct integer,answers jsonb,time_used integer,date timestamptz default now());create table if not exists public.config(key text primary key,value text);insert into public.config(key,value)values('admin_whatsapp','2348000000000')on conflict(key)do nothing;alter table public.profiles enable row level security;alter table public.exams enable row level security;alter table public.results enable row level security;alter table public.config enable row level security;create policy p1 on public.profiles for all using(true)with check(true);create policy p2 on public.exams for all using(true)with check(true);create policy p3 on public.results for all using(true)with check(true);create policy p4 on public.config for all using(true)with check(true);
